30	
31	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
32	
33	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
34	
35	const ITEM_SURCHARGES: Array<ItemSurcharge> = [
36	  { applies: (item) => item.cursed === true, rate: 0.5 },
37	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: 0.3 },
38	];
